// per-family open-source license (OFL / Apache / UFL), baked above from the google/fonts source repo
// (the dir a family lives in IS its license). Lets the app surface the real license per Google font so
// a user never re-confirms each one. Undefined for the few families not matched in the repo (honest
// generic fallback). Built once into a slug→license map.
const _gfLicSlug = (family: string) => family.toLowerCase().replace(/[^a-z0-9]/g, "");
const _gfLicMap = new Map<string, GFLicense | undefined>(GOOGLE_FONTS_ALL.map((g) => [_gfLicSlug(g.family), g.license]));
export const gfLicenseFor = (family: string): GFLicense | undefined => _gfLicMap.get(_gfLicSlug(family));
